@namespace sv_066a91f456f24efcb1620cd17be88479.Components.Pages.Board

<div class="task-card">
    <h4 class="task-title">@Task.Title</h4>
    <p class="task-assignee">@Task.Assignee</p>
    <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <span class="task-due-date">@Task.DueDate.ToString("MMM dd")</span>

    <div class="task-actions">
        @if (CanMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeft" disabled="@IsMoving">← Move Left</button>
        }
        @if (CanMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRight" disabled="@IsMoving">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }
    [Parameter] public bool IsMoving { get; set; }
}

@namespace sv_066a91f456f24efcb1620cd17be88479.Components.Pages.Board

@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="title" />
        <input type="text" placeholder="Assignee" @bind="assignee" />
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="dueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@isSaving">Save</button>
            <button class="btn-cancel" @onclick="Cancel">Cancel</button>
        </div>
        @if (!string.IsNullOrEmpty(error))
        {
            <p class="form-error">@error</p>
        }
    </div>
}

@code {
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;
    private string? error;

    [Parameter, EditorRequired] public string ColumnStatus { get; set; } = default!;
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
        {
            error = "Title is required.";
            return;
        }

        isSaving = true;
        error = null;
        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            IsVisible = false;
            ResetForm();
        }
        catch (Exception ex)
        {
            error = $"Failed to create task: {ex.Message}";
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
        error = null;
    }
}

@namespace sv_066a91f456f24efcb1620cd17be88479.Components.Pages.Board

<div class="kanban-column">
    <div class="column-header">
        <h3>@Title <span class="task-count">(@Tasks.Count)</span></h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => MoveLeft(task)"
                      OnMoveRight="() => MoveRight(task)" />
        }
    </div>

    <div class="column-footer">
        <AddTaskForm ColumnStatus="@Status"
                     TaskService="TaskService"
                     OnTaskCreated="OnTaskCreated" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private int? movingTaskId;

    private async Task MoveLeft(TaskItem task)
    {
        if (LeftStatus is null) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, LeftStatus));
        movingTaskId = null;
    }

    private async Task MoveRight(TaskItem task)
    {
        if (RightStatus is null) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, RightStatus));
        movingTaskId = null;
    }
}

@namespace sv_066a91f456f24efcb1620cd17be88479.Components.Pages.Board

<div class="board-search">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await OnSearchChanged.InvokeAsync(value);
    }
}

