@namespace sv_066a91f456f24efcb1620cd17be88479.Components.Pages.Board

<div class="kanban-column">
    <div class="column-header">
        <h3>@Title <span class="task-count">(@Tasks.Count)</span></h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      CanMoveLeft="CanMoveLeft"
                      CanMoveRight="CanMoveRight"
                      IsMoving="movingTaskId == task.Id"
                      OnMoveLeft="() => MoveLeft(task)"
                      OnMoveRight="() => MoveRight(task)" />
        }
    </div>

    <div class="column-footer">
        <AddTaskForm ColumnStatus="@Status"
                     TaskService="TaskService"
                     OnTaskCreated="OnTaskCreated" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter, EditorRequired] public ITaskService TaskService { get; set; } = default!;

    private int? movingTaskId;

    private async Task MoveLeft(TaskItem task)
    {
        if (LeftStatus is null) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, LeftStatus));
        movingTaskId = null;
    }

    private async Task MoveRight(TaskItem task)
    {
        if (RightStatus is null) return;
        movingTaskId = task.Id;
        await OnTaskMoved.InvokeAsync((task.Id, RightStatus));
        movingTaskId = null;
    }
}

