@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return tasks.ToList();
    }

    private void HandleSearchChanged(string term)
    {
        searchTerm = term;
    }

    private void HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var index = allTasks.FindIndex(t => t.Id == move.TaskId);
            if (index >= 0)
            {
                var existing = allTasks[index];
                allTasks[index] = existing with { Status = move.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }
}

